const express = require('express');
const bodyParser = require('body-parser');
const redis = require('redis');
const twilio = require('twilio');
const crypto = require('crypto');

const app = express();
const redisClient = redis.createClient();
const twilioClient = twilio('TWILIO_ACCOUNT_SID', 'TWILIO_AUTH_TOKEN');

app.use(bodyParser.json());

const users = {}; // In-memory user store for demonstration
const attempts = {}; // Track attempts for each user

app.post('/send-code', (req, res) => {
    const { phoneNumber, userId } = req.body;
    const code = Math.floor(100000 + Math.random() * 900000).toString();
    
    redisClient.setex(`mfa:${userId}`, 600, code);
    twilioClient.messages.create({
        body: `Your verification code is ${code}`,
        from: 'TWILIO_PHONE_NUMBER',
        to: phoneNumber
    }).then(() => {
        attempts[userId] = 0; // Reset attempts on code send
        res.status(200).send('Code sent');
    }).catch(err => {
        res.status(500).send('Error sending code');
    });
});

app.post('/verify-code', (req, res) => {
    const { userId, code } = req.body;

    if (attempts[userId] >= 10) {
        return res.status(403).send('Too many attempts, please try again later');
    }

    redisClient.get(`mfa:${userId}`, (err, storedCode) => {
        if (err || !storedCode) {
            return res.status(400).send('Code expired or not found');
        }

        if (storedCode === code) {
            delete attempts[userId]; // Clear attempts on success
            redisClient.del(`mfa:${userId}`); // Remove code from Redis
            res.status(200).send('Access granted');
        } else {
            attempts[userId] = (attempts[userId] || 0) + 1;
            res.status(400).send('Invalid code');
        }
    });
});

